import type * as React from "react"

/** Identifies one cell by its TanStack row id and column id. */
export type CellPos = { rowId: string; columnId: string }

/** Direction vocabulary shared with table-fields' FieldEditContext. */
export type MoveDirection = "next" | "prev" | "up" | "down"

/** Per-column metadata stashed on ColumnDef.meta by defineColumns. */
export type DataTableColumnMeta = {
  /** Per-column editable override; undefined falls back to the table default. */
  editable?: boolean
  /** Plain-text label for UI that can't render the header function (e.g. the columns menu). */
  label: string
}

/** Supported footer/selection-summary aggregation methods. */
export type AggregationMethod = "sum" | "avg" | "min" | "max" | "count"

/** Dev-declared: which columns support footer aggregation and which methods. */
export type CalculableColumn = {
  columnId: string
  /** Methods offered in the picker; defaults to all five. */
  methods?: AggregationMethod[]
  /** Initial method shown before the user picks one; defaults to off (null). */
  default?: AggregationMethod | null
}

/** Args passed to the dev-supplied computeAggregate callback for scopes that exceed what's loaded client-side. */
export type ComputeAggregateArgs = {
  columnId: string
  method: AggregationMethod
  scope: "all-matching" | "selection-all-matching"
}

/**
 * Lifecycle of a server-computed aggregate value. `idle` before the user has
 * triggered a calculation; `stale` when a prior server value's inputs
 * (method or scope) have since changed but a fresh value hasn't been
 * requested yet. `partial` on a `value`/`stale` state means the number was
 * computed from loaded rows only (no `computeAggregate` was provided even
 * though the scope exceeds what's loaded) — the UI shows a qualifier rather
 * than silently presenting a wrong-looking total as authoritative.
 */
export type AggregateCellState =
  | { status: "idle" }
  | { status: "loading" }
  | { status: "value"; value: number; partial?: boolean }
  | { status: "stale"; value: number; partial?: boolean }
  | { status: "error"; message: string }

/**
 * The live grid state + actions, provided via React Context so cell renderers
 * (built once per column by defineColumns) can read/act without prop-drilling.
 */
export type DataTableRuntime = {
  /** The single focused cell, or null before any cell has been clicked/tabbed to. */
  activeCell: CellPos | null
  /** The cell currently rendering its `edit` UI, or null when nothing is being edited. */
  editingCell: CellPos | null
  /** `pos === activeCell` — a convenience predicate so cell renderers don't do their own equality checks. */
  isActive: (pos: CellPos) => boolean
  /** `pos === editingCell` — same convenience as `isActive`, for the edit-mode branch. */
  isEditing: (pos: CellPos) => boolean
  /** Focuses a cell without entering edit mode (click, or arrow/Tab navigation). */
  setActiveCell: (pos: CellPos) => void
  /** Enters edit mode for `pos`; a no-op if `isColumnEditable(pos.columnId)` is false. */
  beginEdit: (pos: CellPos) => void
  /** Exits edit mode (on commit or cancel) without changing `activeCell`. */
  stopEditing: () => void
  /**
   * Moves `activeCell` one step in the given direction and exits edit mode.
   * "next"/"prev" move horizontally and wrap to the next/previous row at a row
   * edge; "up"/"down" move vertically and clamp (do not wrap) at the grid edge.
   */
  moveActive: (dir: MoveDirection) => void
  /** Resolves the column's `DataTableColumnMeta.editable` override against the table-level default (set in useDataTable). */
  isColumnEditable: (columnId: string) => boolean
  /** Reports an intended cell edit. The raw, field-supplied value — callers own coercion/validation; the library never mutates `data` itself. */
  updateData: (rowId: string, columnId: string, value: unknown) => void
  /** Wired once on the grid's root element (not per-cell) to drive arrow-key/Tab/Enter navigation of the active cell. */
  handleKeyDown: (e: React.KeyboardEvent) => void
  /** Whether pagination is server-driven (useDataTable's manualPagination option) — lets cell renderers (row-gutter, footer) tell whether more rows exist beyond what's loaded. */
  manualPagination: boolean
  /** Total row count across all pages when manualPagination is true; undefined for client-side pagination, where loaded rows already are all rows. */
  totalRowCount: number | undefined
  /**
   * True once the user's select-all click cycle has advanced past "every
   * loaded/filtered row" to "every row matching the current filter,
   * including any not yet loaded" — a logical selection, not a
   * materialization of every id. Only meaningful when `totalRowCount`
   * exceeds the loaded row count; otherwise selecting every loaded row
   * already means "everything," and this stays false.
   */
  isAllMatchingSelected: boolean
  /**
   * Sets `isAllMatchingSelected`. Turning it on also selects every
   * currently-loaded row (via the table's own row-selection state) so the
   * visible checkboxes agree with the logical "everything" state; turning
   * it off does NOT automatically deselect loaded rows, since the caller
   * may be narrowing from "all-matching" back to "all loaded" rather than
   * to "none" — the row-gutter's click-cycle (a later task) owns that
   * distinction and calls the appropriate table method itself when needed.
   */
  setAllMatchingSelected: (matching: boolean) => void
  /**
   * Selects/deselects a single row by id. When `shiftKey` is true and a
   * prior call has recorded an anchor row, every row between the anchor and
   * `rowId` (inclusive, resolved by their live position in the current row
   * model) is set to `checked` instead of toggling just the one row —
   * Sheets/Gmail-style range select. Always updates the anchor to `rowId`
   * afterward, shift-click or not. Takes an id rather than a positional
   * index deliberately: TanStack's `Row.index` is fixed at row creation to
   * the row's position in the original, unsorted data, not its current
   * on-screen position, so an index captured at click time can point at the
   * wrong row (or nothing) once sorting/filtering has reordered the table.
   */
  toggleRowSelected: (rowId: string, checked: boolean, shiftKey: boolean) => void
}

import type { AggregationMethod } from "./types"

/**
 * Pure aggregation over numeric values, shared by the footer's client-side
 * scope and (by convention — the dev's own `computeAggregate` implementation
 * is expected to mirror this) the server path.
 *
 * `count` counts every value regardless of blankness (matches "row count"
 * semantics); sum/avg/min/max ignore null/undefined/NaN entries so a blank
 * cell doesn't corrupt the result. An all-blank/empty input returns 0 for
 * sum (the additive identity) and NaN for avg/min/max, since there's no
 * meaningful average/min/max of nothing — callers format NaN as an em dash
 * rather than the literal string "NaN".
 */
export function aggregate(
  method: AggregationMethod,
  values: (number | null | undefined)[],
): number {
  if (method === "count") return values.length

  const nums = values.filter((v): v is number => v != null && !Number.isNaN(v))
  switch (method) {
    case "sum":
      return nums.reduce((a, b) => a + b, 0)
    case "avg":
      return nums.length === 0 ? Number.NaN : nums.reduce((a, b) => a + b, 0) / nums.length
    case "min":
      return nums.length === 0 ? Number.NaN : Math.min(...nums)
    case "max":
      return nums.length === 0 ? Number.NaN : Math.max(...nums)
  }
}

/** Human-readable labels for the method picker UI. */
export const AGGREGATION_METHOD_LABELS: Record<AggregationMethod, string> = {
  sum: "Sum",
  avg: "Average",
  min: "Min",
  max: "Max",
  count: "Count",
}

/** Ordered list of all methods, for the picker's option list. */
export const ALL_AGGREGATION_METHODS: AggregationMethod[] = ["sum", "avg", "min", "max", "count"]

"use client"

import * as React from "react"

import type { CellPos, MoveDirection } from "./types"

export type UseGridNavigationOptions = {
  rowIds: string[]
  columnIds: string[]
  isColumnEditable: (columnId: string) => boolean
}

export type GridNavigation = {
  activeCell: CellPos | null
  editingCell: CellPos | null
  isActive: (pos: CellPos) => boolean
  isEditing: (pos: CellPos) => boolean
  setActiveCell: (pos: CellPos) => void
  beginEdit: (pos: CellPos) => void
  stopEditing: () => void
  moveActive: (dir: MoveDirection) => void
  handleKeyDown: (e: React.KeyboardEvent) => void
}

function samePos(a: CellPos | null, b: CellPos): boolean {
  return a != null && a.rowId === b.rowId && a.columnId === b.columnId
}

/**
 * Pure grid navigation: active/editing cell state + keyboard handling, over
 * plain row/column id lists. No TanStack Table dependency — testable with
 * fabricated ids. `use-data-table.ts` supplies the real ids and combines this
 * with column-editability and data persistence into the full DataTableRuntime.
 *
 * Two responsibilities that belong to `use-data-table.ts`, not here:
 * 1. Memoize `rowIds`/`columnIds` (e.g. `useMemo` over `table.getRowModel().rows`).
 *    `moveActive`/`handleKeyDown` depend on both arrays by reference, so a
 *    fresh array every render defeats memoization on every consumer.
 * 2. Revalidate `activeCell` when the id lists change under it (sort/filter/
 *    delete) — see the comment on the orphaned-id guard in `moveActive` below.
 */
export function useGridNavigation({
  rowIds,
  columnIds,
  isColumnEditable,
}: UseGridNavigationOptions): GridNavigation {
  const [activeCell, setActiveCellState] = React.useState<CellPos | null>(null)
  const [editingCell, setEditingCell] = React.useState<CellPos | null>(null)

  const setActiveCell = React.useCallback((pos: CellPos) => {
    // Focusing a different cell always exits whatever was being edited — a
    // click elsewhere is an implicit "stop editing", not a silent orphan of
    // editingCell (which would otherwise still be "editing" a cell that's no
    // longer active, while the newly active cell shows no editor).
    setEditingCell(null)
    setActiveCellState(pos)
  }, [])

  const beginEdit = React.useCallback(
    (pos: CellPos) => {
      if (!isColumnEditable(pos.columnId)) return
      setActiveCellState(pos)
      setEditingCell(pos)
    },
    [isColumnEditable],
  )

  const stopEditing = React.useCallback(() => {
    setEditingCell(null)
  }, [])

  const moveActive = React.useCallback(
    (dir: MoveDirection) => {
      setEditingCell(null)
      setActiveCellState((current) => {
        if (rowIds.length === 0 || columnIds.length === 0) return current
        if (!current) return { rowId: rowIds[0], columnId: columnIds[0] }

        const rowIdx = rowIds.indexOf(current.rowId)
        const colIdx = columnIds.indexOf(current.columnId)
        // `current` points at a row/column id no longer in the live lists —
        // e.g. a sort/filter/delete on the table removed it while it was
        // active. This hook is deliberately table-agnostic (see the module
        // doc comment) and has no principled way to pick a replacement
        // position, so it holds still rather than guessing. The owner of
        // `rowIds`/`columnIds` (use-data-table.ts) is responsible for
        // resetting or revalidating `activeCell` — e.g. via setActiveCell —
        // when the id lists it derives from the table change out from under
        // an active cell; a silently-frozen active cell is otherwise a real
        // dead end for keyboard navigation.
        if (rowIdx === -1 || colIdx === -1) return current

        if (dir === "up") {
          return { rowId: rowIds[Math.max(0, rowIdx - 1)], columnId: current.columnId }
        }
        if (dir === "down") {
          return {
            rowId: rowIds[Math.min(rowIds.length - 1, rowIdx + 1)],
            columnId: current.columnId,
          }
        }
        if (dir === "prev") {
          if (colIdx > 0) return { rowId: current.rowId, columnId: columnIds[colIdx - 1] }
          if (rowIdx > 0) {
            return { rowId: rowIds[rowIdx - 1], columnId: columnIds[columnIds.length - 1] }
          }
          return current
        }
        // "next"
        if (colIdx < columnIds.length - 1) {
          return { rowId: current.rowId, columnId: columnIds[colIdx + 1] }
        }
        if (rowIdx < rowIds.length - 1) {
          return { rowId: rowIds[rowIdx + 1], columnId: columnIds[0] }
        }
        return current
      })
    },
    [rowIds, columnIds],
  )

  const handleKeyDown = React.useCallback(
    (e: React.KeyboardEvent) => {
      if (editingCell) {
        if (e.key === "Escape") {
          stopEditing()
          e.preventDefault()
        }
        return
      }
      if (!activeCell) return
      switch (e.key) {
        case "ArrowUp":
          moveActive("up")
          e.preventDefault()
          break
        case "ArrowDown":
          moveActive("down")
          e.preventDefault()
          break
        case "ArrowLeft":
          moveActive("prev")
          e.preventDefault()
          break
        case "ArrowRight":
          moveActive("next")
          e.preventDefault()
          break
        case "Tab":
          moveActive(e.shiftKey ? "prev" : "next")
          e.preventDefault()
          break
        case "Enter":
          beginEdit(activeCell)
          e.preventDefault()
          break
        default:
          break
      }
    },
    [activeCell, editingCell, moveActive, beginEdit, stopEditing],
  )

  return {
    activeCell,
    editingCell,
    isActive: (pos) => samePos(activeCell, pos),
    isEditing: (pos) => samePos(editingCell, pos),
    setActiveCell,
    beginEdit,
    stopEditing,
    moveActive,
    handleKeyDown,
  }
}

"use client"

import * as React from "react"
import type { Table } from "@tanstack/react-table"

import { aggregate } from "./aggregate"
import type {
  AggregateCellState,
  AggregationMethod,
  CalculableColumn,
  ComputeAggregateArgs,
} from "./types"

export type UseFooterAggregationOptions<TData> = {
  table: Table<TData>
  calculableColumns?: CalculableColumn[]
  computeAggregate?: (args: ComputeAggregateArgs) => Promise<number>
  manualPagination?: boolean
  totalRowCount?: number
  isAllMatchingSelected: boolean
}

export type FooterAggregationResult = {
  /** Live method per calculable column; null means "off" (no footer value shown). */
  methods: Record<string, AggregationMethod | null>
  setMethod: (columnId: string, method: AggregationMethod | null) => void
  /** Resolved display state for a column's current method, or undefined if the column isn't calculable or its method is off. */
  stateFor: (columnId: string) => AggregateCellState | undefined
  /** True when the footer is summarizing a selection rather than all visible rows. */
  scopeIsSelection: boolean
  /** Re-requests a server value for a column currently showing a "Calculate" trigger (idle) or a stale value. */
  calculate: (columnId: string) => void
}

export function useFooterAggregation<TData>({
  table,
  calculableColumns = [],
  computeAggregate,
  manualPagination = false,
  totalRowCount,
  isAllMatchingSelected,
}: UseFooterAggregationOptions<TData>): FooterAggregationResult {
  const columnConfig = React.useMemo(() => {
    const map = new Map<string, CalculableColumn>()
    for (const c of calculableColumns) map.set(c.columnId, c)
    return map
  }, [calculableColumns])

  const [methods, setMethods] = React.useState<Record<string, AggregationMethod | null>>(() => {
    const initial: Record<string, AggregationMethod | null> = {}
    for (const c of calculableColumns) initial[c.columnId] = c.default ?? null
    return initial
  })

  const setMethod = React.useCallback((columnId: string, method: AggregationMethod | null) => {
    setMethods((prev) => ({ ...prev, [columnId]: method }))
  }, [])

  const selectedRows = table.getSelectedRowModel().rows
  const scopeIsSelection = isAllMatchingSelected || selectedRows.length > 0
  const scopeRows = scopeIsSelection ? selectedRows : table.getSortedRowModel().rows

  const loadedRowCount = table.getSortedRowModel().rows.length
  // Only the all-matching selection can ever exceed what's loaded — a
  // hand-picked selection of specific rows is, by definition, a selection of
  // rows the user could see (and therefore rows already loaded).
  const scopeExceedsLoaded =
    manualPagination &&
    totalRowCount !== undefined &&
    (scopeIsSelection ? isAllMatchingSelected : totalRowCount > loadedRowCount)

  const [serverStates, setServerStates] = React.useState<Record<string, AggregateCellState>>({})

  // If the user changes method/scope and re-triggers calculate() before an
  // earlier in-flight request for the same column has resolved, the two
  // promises race: whichever settles last would otherwise win, even if it's
  // the stale one. Each calculate() call bumps a per-column request id, and
  // its .then/.catch only commits state if that id is still the latest one
  // recorded for the column when the promise settles — otherwise a newer
  // request has already superseded it and the result is silently dropped.
  const requestIdRef = React.useRef<Record<string, number>>({})

  const calculate = React.useCallback(
    (columnId: string) => {
      const method = methods[columnId]
      if (!method || !computeAggregate) return
      const requestId = (requestIdRef.current[columnId] ?? 0) + 1
      requestIdRef.current[columnId] = requestId
      setServerStates((prev) => ({ ...prev, [columnId]: { status: "loading" } }))
      computeAggregate({
        columnId,
        method,
        scope: scopeIsSelection ? "selection-all-matching" : "all-matching",
      })
        .then((value) => {
          if (requestIdRef.current[columnId] !== requestId) return // superseded by a newer request
          setServerStates((prev) => ({ ...prev, [columnId]: { status: "value", value } }))
        })
        .catch((err: unknown) => {
          if (requestIdRef.current[columnId] !== requestId) return // superseded by a newer request
          const message = err instanceof Error ? err.message : "Failed to calculate"
          setServerStates((prev) => ({ ...prev, [columnId]: { status: "error", message } }))
        })
    },
    [methods, computeAggregate, scopeIsSelection],
  )

  // A resolved server value goes stale when its inputs (method or scope)
  // change since it was last requested — re-derive an identity key per
  // column each render and compare against what was last seen.
  const requestKeyRef = React.useRef<Record<string, string>>({})
  React.useEffect(() => {
    for (const columnId of columnConfig.keys()) {
      const method = methods[columnId]
      const key = `${method ?? ""}:${scopeIsSelection ? "selection" : "all"}`
      const prevKey = requestKeyRef.current[columnId]
      if (prevKey !== undefined && prevKey !== key) {
        setServerStates((prev) => {
          const existing = prev[columnId]
          if (existing?.status === "value") {
            return { ...prev, [columnId]: { status: "stale", value: existing.value } }
          }
          return prev
        })
      }
      requestKeyRef.current[columnId] = key
    }
  }, [methods, scopeIsSelection, columnConfig])

  const stateFor = React.useCallback(
    (columnId: string): AggregateCellState | undefined => {
      const method = methods[columnId]
      if (!columnConfig.has(columnId) || !method) return undefined

      if (scopeExceedsLoaded && computeAggregate) {
        return serverStates[columnId] ?? { status: "idle" }
      }

      const values = scopeRows.map((row) => row.getValue(columnId) as number | null | undefined)
      const value = aggregate(method, values)
      return scopeExceedsLoaded
        ? { status: "value", value, partial: true }
        : { status: "value", value }
    },
    [methods, columnConfig, scopeExceedsLoaded, computeAggregate, serverStates, scopeRows],
  )

  return { methods, setMethod, stateFor, scopeIsSelection, calculate }
}

"use client"

import * as React from "react"

import type { DataTableRuntime } from "./types"

/**
 * Carries the live DataTableRuntime (active/editing cell, navigation,
 * updateData) to cell renderers built by defineColumns, without prop-drilling
 * through every ColumnDef. Null outside a <DataTable> (or when a column
 * built with defineColumns is rendered in a plain table — see define-columns.ts's
 * fallback-to-display behavior in that case).
 */
export const DataTableRuntimeContext = React.createContext<DataTableRuntime | null>(null)

export function useDataTableRuntime(): DataTableRuntime | null {
  return React.useContext(DataTableRuntimeContext)
}

"use client"

import * as React from "react"
import type { CellContext, ColumnDef } from "@tanstack/react-table"

import {
  buttonField,
  checkboxField,
  currencyField,
  dateField,
  durationField,
  emailField,
  longTextField,
  multiSelectField,
  numberField,
  percentField,
  phoneField,
  ratingField,
  singleSelectField,
  textField,
  urlField,
  type FieldType,
  type SelectOption,
} from "@/components/table-fields"

import { useDataTableRuntime } from "./data-table-runtime-context"
import type { CellPos, DataTableColumnMeta } from "./types"

/**
 * Keys of TData whose value type extends V. Powers col.number("age")
 * type-checking. Note this is a BIDIRECTIONAL extends check (`TData[K]
 * extends V ? (V extends TData[K] ? K : never) : never`), i.e. an exact-type
 * match rather than a one-directional "assignable to V" check — `-?` also
 * strips optionality before comparing. This is deliberate: it's what makes
 * `col.text` reject a field typed `string | undefined` (which is assignable
 * to `string` in one direction but not exact). Don't "simplify" this to a
 * plain one-directional `extends` — that would silently accept wider types.
 */
type KeysMatching<TData, V> = {
  [K in keyof TData]-?: TData[K] extends V ? (V extends TData[K] ? K : never) : never
}[keyof TData] &
  string

type ColumnOptions = {
  /** Overrides the auto-generated (capitalized-key) header label. */
  header?: string
  /** Per-column editable override; undefined falls back to the table default. */
  editable?: boolean
  /** Whether the column can be sorted. Defaults to true (false for col.button). */
  enableSorting?: boolean
  /** Whether the column can be hidden via the columns menu. Defaults to true. */
  enableHiding?: boolean
  /** Whether the column can be pinned. Defaults to true. */
  enablePinning?: boolean
  /** Whether the column can be resized. Defaults to true. */
  enableResizing?: boolean
  /** Fixed column width in pixels; undefined lets TanStack use its default. */
  size?: number
}

// camelCase accessor keys aren't word-split (e.g. "firstName" only gets its
// first letter capitalized, not turned into "First Name") — pass an explicit
// `header` for multi-word keys.
function labelFor(key: string, header?: string): string {
  if (header) return header
  return key.charAt(0).toUpperCase() + key.slice(1)
}

/**
 * Renders a field's display or edit UI depending on live DataTableRuntime
 * state. Built once per column (stable identity across renders), so it can
 * hold its own local "staged" edit value via useState — `field.edit` itself
 * is a plain function (not a component), so all editing state lives here,
 * one level up, and is handed to `field.edit` through FieldEditContext.
 */
function makeFieldCell<TData, V>(
  field: FieldType<V>,
  columnEditableOverride: boolean | undefined,
) {
  return function FieldCell(ctx: CellContext<TData, unknown>) {
    const runtime = useDataTableRuntime()
    const value = ctx.getValue() as V
    const pos: CellPos = { rowId: ctx.row.id, columnId: ctx.column.id }
    const [staged, setStaged] = React.useState<V>(value)
    // isEditing and isActive must both be computed before any hook call below
    // (Rules of Hooks forbid calling useEffect only on some render paths), so
    // they can't be read from `runtime` after the `if (!runtime)` early
    // return.
    const isEditing = runtime ? runtime.isEditing(pos) : false
    const isActive = runtime ? runtime.isActive(pos) : false
    const cellRef = React.useRef<HTMLDivElement>(null)
    // Captured in onMouseDown, read in onClick — see the comment on
    // onMouseDown below for why onClick can't just read `isActive` directly.
    const wasActiveBeforeMouseDownRef = React.useRef(false)

    React.useEffect(() => {
      if (isEditing) setStaged(value)
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isEditing])

    // Keep real DOM focus in sync with the logical active cell — arrow-key/
    // Tab navigation (useGridNavigation.moveActive) only updates React state,
    // it never calls .focus() itself. Without this, document.activeElement
    // can drift from the cell that's visually/logically active, which is a
    // real screen-reader bug even though keyboard nav still mechanically
    // works (the keydown listener sits on an ancestor and catches bubbled
    // events regardless of which descendant has focus).
    //
    // Depends on BOTH [isActive, isEditing], not just [isActive]: this cell's
    // <div ref={cellRef}> is unmounted while isEditing is true (the
    // `field.edit(...)` branch below returns a completely different tree,
    // e.g. an <input>) and remounted — a fresh DOM node, ref reattached from
    // scratch — the moment isEditing flips back to false. beginEdit/
    // stopEditing never touch activeCell, so a cell can stay active the
    // entire time isEditing goes true→false (Escape, or committing an edit);
    // with only [isActive] as the dependency, isActive never changes across
    // that cycle, so the effect wouldn't rerun and the newly-remounted div
    // would never get focused — document.activeElement would fall back to
    // <body> (whatever last had focus, e.g. the just-unmounted <input>) even
    // though the ring still shows this cell as active. That's not just a
    // cosmetic miss: with focus on <body>, the wrapper's onKeyDown (bound on
    // a div that is an ANCESTOR of body's children, not of body itself) never
    // sees the event — Enter, arrows, everything silently does nothing until
    // the user clicks again. Depending on isEditing too makes the effect
    // rerun exactly on that remount and reclaim focus. Still can't steal
    // focus from an editor mid-edit in another cell (that cell's own isActive
    // is false) and still can't loop (calling .focus() here re-triggers this
    // cell's onFocus → setActiveCell with the same pos, a same-value update:
    // isActive and isEditing both stay put, so this effect's deps don't
    // change and it doesn't refire).
    React.useEffect(() => {
      if (isActive && !isEditing) cellRef.current?.focus()
    }, [isActive, isEditing])

    if (!runtime) {
      // No <DataTable> runtime in scope — degrade to a plain read-only cell.
      return field.display(ctx as CellContext<unknown, V>)
    }

    const editable =
      (columnEditableOverride ?? runtime.isColumnEditable(pos.columnId)) && Boolean(field.edit)

    if (isEditing && field.edit) {
      return field.edit({
        value: staged,
        setValue: setStaged,
        commit: () => {
          runtime.updateData(pos.rowId, pos.columnId, staged)
          runtime.stopEditing()
        },
        cancel: () => runtime.stopEditing(),
        focusNext: (dir) => {
          // moveActive already clears editingCell internally, so an explicit
          // stopEditing() here would be redundant.
          runtime.moveActive(dir)
        },
      })
    }

    return (
      <div
        ref={cellRef}
        tabIndex={0}
        data-active={isActive ? "true" : undefined}
        // A real mouse click dispatches `mousedown` → native focus move →
        // `focus` → `mouseup` → `click`, as separate top-level browser
        // events. Each one gets its own React commit, so by the time
        // `onClick` runs, the `focus` event above has *already* called
        // `runtime.setActiveCell(pos)` and re-rendered this cell with
        // `isActive: true` — even on a cell that was NOT active before this
        // click. Reading `isActive` inside `onClick` therefore can't tell
        // "was already active" (click #2, should edit) apart from "just
        // became active via this click's own focus event" (click #1, should
        // only activate): both read `isActive === true`. Every first click on
        // an inactive editable cell would incorrectly jump straight to edit
        // mode. `onMouseDown` fires BEFORE the browser moves focus, so it's
        // the only handler that sees the true pre-click state; capture it
        // here and have onClick decide off the captured ref instead of the
        // (by-then-stale-for-this-purpose) live `isActive`.
        onMouseDown={() => {
          wasActiveBeforeMouseDownRef.current = isActive
        }}
        onClick={() => {
          if (wasActiveBeforeMouseDownRef.current && editable) runtime.beginEdit(pos)
          else runtime.setActiveCell(pos)
        }}
        onFocus={() => runtime.setActiveCell(pos)}
        className="overflow-hidden text-ellipsis whitespace-nowrap rounded-sm px-2 py-1 outline-none data-[active=true]:ring-2 data-[active=true]:ring-ring data-[active=true]:ring-inset"
      >
        {field.display(ctx as CellContext<unknown, V>)}
      </div>
    )
  }
}

function buildColumn<TData, V>(
  field: FieldType<V>,
  key: string,
  opts: ColumnOptions = {},
  buildOpts: { noAccessor?: boolean } = {},
): ColumnDef<TData, unknown> {
  // A column whose field has no `edit` renderer (e.g. col.multiSelect,
  // col.button) can never actually be edited, no matter what the table-level
  // default or an explicit opts.editable says — editing without an editor is
  // meaningless. Forcing `editable: false` here (an explicit false, not
  // undefined) makes isColumnEditable's `override ?? tableDefault`
  // resolution (use-data-table.ts) correctly return false for these columns
  // regardless of the table default, which in turn makes
  // useGridNavigation.beginEdit's existing isColumnEditable check correctly
  // refuse to enter edit mode via Enter — closing the gap at the source
  // instead of teaching beginEdit about field.edit. When field.edit IS
  // defined, this passes opts.editable through unchanged (including
  // undefined, which correctly falls back to the table default).
  const editable = field.edit ? opts.editable : false
  const meta: DataTableColumnMeta = { editable, label: labelFor(key, opts.header) }
  return {
    id: key,
    // `key` is a validated TData key for every field method except
    // col.button (where `noAccessor` is set and this line is skipped
    // entirely — see below). `as never` sidesteps ColumnDef's accessorKey
    // overload resolution, which otherwise can't unify with the generic `V`
    // used here; `keyof TData & string` doesn't type-check because TData
    // isn't statically known to have a string-keyed shape at this call site.
    ...(buildOpts.noAccessor ? {} : { accessorKey: key as never }),
    header: meta.label,
    cell: makeFieldCell<TData, V>(field, editable),
    meta,
    enableSorting: opts.enableSorting ?? true,
    enableHiding: opts.enableHiding ?? true,
    enablePinning: opts.enablePinning ?? true,
    enableResizing: opts.enableResizing ?? true,
    size: opts.size,
  }
}

/**
 * Returns a typed `col` builder closed over TData. Each method constrains its
 * accessor key to a TData key whose value type matches the field (e.g.
 * `col.number` only accepts keys typed `number`), and returns a ColumnDef
 * ready to drop into `columns: [...]`.
 */
export function defineColumns<TData>() {
  return {
    text: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(textField(), key, opts),
    longText: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(longTextField(), key, opts),
    url: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(urlField(), key, opts),
    email: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(emailField(), key, opts),
    phone: (key: KeysMatching<TData, string>, opts?: ColumnOptions) =>
      buildColumn<TData, string>(phoneField(), key, opts),
    number: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { locale?: string; maximumFractionDigits?: number },
    ) => buildColumn<TData, number>(numberField(opts), key, opts),
    currency: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { currency?: string; locale?: string },
    ) => buildColumn<TData, number>(currencyField(opts), key, opts),
    percent: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { locale?: string; maximumFractionDigits?: number },
    ) => buildColumn<TData, number>(percentField(opts), key, opts),
    duration: (
      key: KeysMatching<TData, number>,
      opts?: ColumnOptions & { unit?: "s" | "ms"; maxUnits?: number },
    ) => buildColumn<TData, number>(durationField(opts), key, opts),
    singleSelect: (
      key: KeysMatching<TData, string>,
      opts: ColumnOptions & { options: SelectOption[] },
    ) => buildColumn<TData, string>(singleSelectField(opts), key, opts),
    multiSelect: (
      key: KeysMatching<TData, string[]>,
      opts: ColumnOptions & { options: SelectOption[] },
    ) => buildColumn<TData, string[]>(multiSelectField(opts), key, opts),
    checkbox: (key: KeysMatching<TData, boolean>, opts?: ColumnOptions) =>
      buildColumn<TData, boolean>(checkboxField(), key, opts),
    rating: (key: KeysMatching<TData, number>, opts?: ColumnOptions & { max?: number }) =>
      buildColumn<TData, number>(ratingField(opts), key, opts),
    date: (
      key: KeysMatching<TData, Date | string>,
      opts?: ColumnOptions & { withTime?: boolean; locale?: string },
    ) => buildColumn<TData, Date | string>(dateField(opts), key, opts),
    button: (
      id: string,
      opts: ColumnOptions & { label: string; onClick: (row: TData) => void },
    ) =>
      // buttonField's display never reads ctx.getValue() — it's an action
      // column, not a data column — so it defaults to unsortable (still
      // overridable via an explicit opts.enableSorting) and has no real
      // TData accessor (id-only display column; see buildColumn's
      // `noAccessor`), since `id` here is just an identifier, not a key into
      // TData.
      buildColumn<TData, unknown>(
        buttonField<TData>(opts),
        id,
        { ...opts, enableSorting: opts.enableSorting ?? false },
        { noAccessor: true },
      ),
  }
}

