import type { CellContext, ColumnDef, HeaderContext } from "@tanstack/react-table"
import { Minus } from "lucide-react"
import * as React from "react"

import { Checkbox } from "@/components/ui/checkbox"
import { cn } from "@/lib/utils"

import { useDataTableRuntime } from "./data-table-runtime-context"

/** Stable id for the injected leading gutter column (row numbers + selection). */
export const ROW_GUTTER_COLUMN_ID = "__row-gutter__"

function SelectAllHeader<TData>({ table }: HeaderContext<TData, unknown>) {
  const runtime = useDataTableRuntime()
  const isAllMatchingSelected = runtime?.isAllMatchingSelected ?? false
  const hasMoreThanLoaded =
    (runtime?.manualPagination ?? false) &&
    (runtime?.totalRowCount ?? 0) > table.getFilteredRowModel().flatRows.length

  const allPageSelected = table.getIsAllPageRowsSelected()
  const allLoadedSelected = table.getIsAllRowsSelected()
  const someSelected = table.getIsSomeRowsSelected() || table.getIsSomePageRowsSelected()

  const checked = isAllMatchingSelected || allLoadedSelected
  const indeterminate = !checked && someSelected

  const ariaLabel = isAllMatchingSelected
    ? "All matching rows selected — deselect"
    : allLoadedSelected
      ? hasMoreThanLoaded
        ? "All loaded rows selected — deselect, or select all matching rows"
        : "Deselect all rows"
      : someSelected
        ? "Some rows selected — select all"
        : "Select all rows"

  function handleClick() {
    if (isAllMatchingSelected) {
      runtime?.setAllMatchingSelected(false)
      table.toggleAllRowsSelected(false)
      return
    }
    if (allLoadedSelected) {
      if (hasMoreThanLoaded) runtime?.setAllMatchingSelected(true)
      else table.toggleAllRowsSelected(false)
      return
    }
    if (allPageSelected) {
      table.toggleAllRowsSelected(true)
      return
    }
    table.toggleAllPageRowsSelected(true)
  }

  return (
    <div className="relative inline-flex items-center justify-center">
      <Checkbox
        checked={checked}
        indeterminate={indeterminate}
        onCheckedChange={handleClick}
        aria-label={ariaLabel}
        className={indeterminate ? "[&_svg]:opacity-0" : undefined}
      />
      {indeterminate ? (
        <Minus className="pointer-events-none absolute size-3" aria-hidden="true" />
      ) : null}
    </div>
  )
}

function RowGutterCell<TData>({ row, table }: CellContext<TData, unknown>) {
  const runtime = useDataTableRuntime()
  const selected = row.getIsSelected()
  // Captured on pointerdown (fires well before the click that triggers
  // onCheckedChange) rather than read off onCheckedChange's own event
  // payload — base-ui's `eventDetails.event` carries the native event, but
  // Radix's onCheckedChange is `(checked) => void` with no second argument
  // at all (a long-standing gap — radix-ui/primitives#734), and this file
  // ships unmodified to the data-table-radix registry item (no
  // row-gutter.radix.tsx twin needed: onPointerDown is a plain DOM prop
  // both primitives forward to their underlying element, so this works
  // identically on both builds).
  const shiftKeyRef = React.useRef(false)
  // `pagination` is an unconditional built-in TanStack feature — the state
  // key always exists (default `{pageIndex: 0, pageSize: 10}`) even when
  // `enablePagination` is false, so this is never undefined in practice.
  const { pageIndex, pageSize } = table.getState().pagination
  // `row.index` is NOT this row's position in the currently-displayed order
  // — it's fixed at row creation to the row's index in its parent array
  // (i.e. the original, unsorted `data`), and getSortedRowModel preserves it
  // via a shallow copy (`{...row}`) rather than reassigning it. Sorting a
  // column then leaves `row.index` scrambled relative to what's on screen.
  // The row's real display position is its index within the current row
  // model instead — looked up by id, not by reference: the `row` this cell
  // receives via CellContext and the entries in `table.getRowModel().rows`
  // are logically the same row but NOT the same object (getSortedRowModel
  // rebuilds a fresh `{...row}` copy per row on each recomputation), so
  // `indexOf(row)` always misses and silently returns -1.
  const displayIndex = table.getRowModel().rows.findIndex((r) => r.id === row.id)
  const rowNumber = pageIndex * pageSize + displayIndex + 1

  // Both the number and the checkbox are always mounted; only their CSS
  // visibility toggles. An earlier version tracked hover via onMouseEnter/
  // onMouseLeave React state, but the shared Checkbox primitive gives itself
  // an oversized invisible touch target (`after:-inset-x-3 after:-inset-y-2`
  // in components/ui/checkbox.tsx) for accessibility — that hit region
  // spills a few pixels past this cell's own bounds into the row above/
  // below, so the pointer can cross into a neighboring row's territory
  // without ever firing this row's mouseleave, leaving its checkbox stuck
  // visible. Driving visibility from real-time `:hover`/`:focus-within`
  // instead of discrete enter/leave events sidesteps that entirely — CSS
  // pseudo-classes re-evaluate continuously from actual cursor/focus
  // position, so there's nothing to get "stuck". `[tr:hover_&]` (already
  // used the same way for pinned-column highlighting in data-table.tsx)
  // reveals on hovering anywhere in the row, not just this narrow cell,
  // matching the row's own native hover background. `group`/
  // `group-focus-within` keep it keyboard-reachable: tabbing onto this
  // cell's div reveals the checkbox so a second Tab can land on it.
  const numberHiddenClass = selected ? "hidden" : "[tr:hover_&]:hidden group-focus-within:hidden"
  const checkboxWrapperClass = selected
    ? "inline-flex"
    : "hidden [tr:hover_&]:inline-flex group-focus-within:inline-flex"

  return (
    <div
      className="group flex h-full items-center justify-center px-2 py-1 text-xs text-muted-foreground"
      tabIndex={0}
      aria-label={selected ? undefined : `Row ${rowNumber}`}
    >
      <span className={cn("tabular-nums", numberHiddenClass)}>{rowNumber}</span>
      <span className={checkboxWrapperClass}>
        <Checkbox
          checked={selected}
          onPointerDown={(e) => {
            shiftKeyRef.current = e.shiftKey
          }}
          onKeyDown={(e) => {
            // Space/Enter-triggered toggles (keyboard activation) never fire
            // pointerdown, so track the modifier here too — otherwise
            // shiftKeyRef could still hold a stale value from an earlier
            // mouse click.
            shiftKeyRef.current = e.shiftKey
          }}
          onCheckedChange={(checked) => {
            runtime?.toggleRowSelected(row.id, checked === true, shiftKeyRef.current)
          }}
          aria-label={selected ? `Deselect row ${rowNumber}` : `Select row ${rowNumber}`}
        />
      </span>
    </div>
  )
}

/**
 * Builds the leading gutter column: row numbers that swap to a selection
 * checkbox on hover (or when the row is selected), plus a tri-state
 * select-all checkbox in the header. Prepended to the user's columns by
 * useDataTable (Task 3) when `enableRowSelection` is true — not part of the
 * `defineColumns` builder, since it's a structural, table-owned column with
 * no TData accessor.
 */
export function buildRowGutterColumn<TData>(): ColumnDef<TData, unknown> {
  return {
    id: ROW_GUTTER_COLUMN_ID,
    header: SelectAllHeader,
    cell: RowGutterCell,
    enableSorting: false,
    enableHiding: false,
    enablePinning: false,
    enableResizing: false,
    size: 40,
  }
}

"use client"

import type { Column } from "@tanstack/react-table"
import { ArrowDown, ArrowUp, ChevronsUpDown } from "lucide-react"
import type * as React from "react"

export function ColumnHeader<TData>({
  column,
  label,
  icon: Icon,
}: {
  column: Column<TData>
  label: React.ReactNode
  icon?: React.ComponentType<{ className?: string }>
}) {
  const canSort = column.getCanSort()

  if (!canSort) {
    return (
      <span className="flex items-center gap-1.5 text-muted-foreground">
        {Icon ? (
          <span aria-hidden="true">
            <Icon className="size-4" />
          </span>
        ) : null}
        {label}
      </span>
    )
  }

  const sorted = column.getIsSorted()
  const sortState =
    sorted === "asc" ? "sorted ascending" : sorted === "desc" ? "sorted descending" : "not sorted"
  const ariaLabel = typeof label === "string" ? `${label}, ${sortState}` : sortState

  return (
    <button
      type="button"
      onClick={column.getToggleSortingHandler()}
      aria-label={ariaLabel}
      className="flex items-center gap-1.5 text-muted-foreground hover:text-foreground"
    >
      {Icon ? (
        <span aria-hidden="true">
          <Icon className="size-4" />
        </span>
      ) : null}
      {label}
      {sorted === "asc" ? (
        <ArrowUp data-sort="asc" className="size-4" aria-hidden="true" />
      ) : sorted === "desc" ? (
        <ArrowDown data-sort="desc" className="size-4" aria-hidden="true" />
      ) : (
        <ChevronsUpDown data-sort="none" className="size-4 opacity-40" aria-hidden="true" />
      )}
    </button>
  )
}

"use client"

import type { Table } from "@tanstack/react-table"
import { ArrowLeftToLine, ArrowRightToLine, Columns3 } from "lucide-react"

import { Button } from "@/components/ui/button"
import { Checkbox } from "@/components/ui/checkbox"
import { Popover, PopoverContent } from "@/components/ui/popover"

import { PopoverButtonTrigger } from "./primitives"
import type { DataTableColumnMeta } from "./types"

export function ColumnsMenuContent<TData>({ table }: { table: Table<TData> }) {
  // Columns that can neither be hidden nor pinned (e.g. row-gutter.tsx's
  // structural selection/row-number column, which sets both to false) have
  // nothing for this menu to offer — every control below is conditional on
  // one of those two capabilities, so such a column would otherwise render
  // as a bare row showing its raw internal id with no controls at all.
  const columns = table.getAllLeafColumns().filter((column) => column.getCanHide() || column.getCanPin())

  return (
    <div className="space-y-0.5">
      {columns.map((column) => {
        const label = (column.columnDef.meta as DataTableColumnMeta | undefined)?.label ?? column.id
        const pinned = column.getIsPinned()
        return (
          <div
            key={column.id}
            className="flex items-center justify-between gap-2 rounded-sm px-1 py-1 text-sm hover:bg-muted"
          >
            <label className="flex flex-1 cursor-pointer items-center gap-2 select-none">
              {column.getCanHide() ? (
                <Checkbox
                  checked={column.getIsVisible()}
                  onCheckedChange={(checked) => column.toggleVisibility(checked === true)}
                />
              ) : null}
              <span className="flex-1">{label}</span>
            </label>
            {column.getCanPin() ? (
              <div className="flex items-center gap-0.5">
                <Button
                  type="button"
                  variant={pinned === "left" ? "secondary" : "ghost"}
                  size="icon-xs"
                  aria-label={`Pin ${label} left`}
                  onClick={() => column.pin(pinned === "left" ? false : "left")}
                >
                  <ArrowLeftToLine className="size-3.5" aria-hidden="true" />
                </Button>
                <Button
                  type="button"
                  variant={pinned === "right" ? "secondary" : "ghost"}
                  size="icon-xs"
                  aria-label={`Pin ${label} right`}
                  onClick={() => column.pin(pinned === "right" ? false : "right")}
                >
                  <ArrowRightToLine className="size-3.5" aria-hidden="true" />
                </Button>
              </div>
            ) : null}
          </div>
        )
      })}
    </div>
  )
}

export function ColumnsMenu<TData>({ table }: { table: Table<TData> }) {
  return (
    <Popover>
      <PopoverButtonTrigger className="gap-2">
        <Columns3 className="size-4" aria-hidden="true" />
        Columns
      </PopoverButtonTrigger>
      <PopoverContent align="start" className="w-64">
        <ColumnsMenuContent table={table} />
      </PopoverContent>
    </Popover>
  )
}

"use client"

import type { Column, Table } from "@tanstack/react-table"
import { Loader2 } from "lucide-react"
import * as React from "react"

import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover"
import { TableCell, TableFooter, TableRow } from "@/components/ui/table"
import { cn } from "@/lib/utils"

import { AGGREGATION_METHOD_LABELS, ALL_AGGREGATION_METHODS } from "./aggregate"
import type { FooterAggregationResult } from "./use-footer-aggregation"
import type { AggregationMethod, DataTableColumnMeta } from "./types"

function formatValue(value: number): string {
  if (Number.isNaN(value)) return "—"
  return new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(value)
}

function FooterMethodPicker({
  columnLabel,
  method,
  onPick,
}: {
  columnLabel: string
  method: AggregationMethod | null
  onPick: (method: AggregationMethod | null) => void
}) {
  const [open, setOpen] = React.useState(false)
  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger
        render={(p) => (
          <button
            {...p}
            type="button"
            aria-label={`${columnLabel} aggregation: ${method ? AGGREGATION_METHOD_LABELS[method] : "off"}`}
            className="rounded-sm px-1.5 py-0.5 text-left text-xs text-muted-foreground hover:bg-muted hover:text-foreground"
          />
        )}
      >
        {method ? AGGREGATION_METHOD_LABELS[method] : "—"}
      </PopoverTrigger>
      <PopoverContent align="start" className="w-36 p-1">
        <button
          type="button"
          className={cn(
            "w-full rounded-sm px-2 py-1 text-left text-sm hover:bg-muted",
            method === null && "font-medium",
          )}
          onClick={() => {
            onPick(null)
            setOpen(false)
          }}
        >
          None
        </button>
        {ALL_AGGREGATION_METHODS.map((m) => (
          <button
            key={m}
            type="button"
            className={cn(
              "w-full rounded-sm px-2 py-1 text-left text-sm hover:bg-muted",
              method === m && "font-medium",
            )}
            onClick={() => {
              onPick(m)
              setOpen(false)
            }}
          >
            {AGGREGATION_METHOD_LABELS[m]}
          </button>
        ))}
      </PopoverContent>
    </Popover>
  )
}

function FooterValueCell<TData>({
  column,
  aggregation,
}: {
  column: Column<TData, unknown>
  aggregation: FooterAggregationResult
}) {
  const isCalculable = aggregation.methods[column.id] !== undefined
  if (!isCalculable) return <TableCell className="p-0" />

  const method = aggregation.methods[column.id] ?? null
  const state = aggregation.stateFor(column.id)
  const columnLabel = (column.columnDef.meta as DataTableColumnMeta | undefined)?.label ?? column.id

  return (
    <TableCell className="p-0 align-middle">
      <div className="flex items-center justify-between gap-1 px-1 py-1">
        <FooterMethodPicker
          columnLabel={columnLabel}
          method={method}
          onPick={(m) => aggregation.setMethod(column.id, m)}
        />
        {method && state ? (
          <span className="truncate text-right text-xs tabular-nums text-muted-foreground">
            {state.status === "idle" ? (
              <button
                type="button"
                className="underline"
                onClick={() => aggregation.calculate(column.id)}
              >
                Calculate
              </button>
            ) : state.status === "loading" ? (
              <Loader2 className="ml-auto size-3 animate-spin" aria-label="Calculating" />
            ) : state.status === "error" ? (
              <button
                type="button"
                className="text-destructive underline"
                onClick={() => aggregation.calculate(column.id)}
              >
                Retry
              </button>
            ) : (
              <>
                {formatValue(state.value)}
                {state.partial ? <span className="ml-1 opacity-70">(loaded rows)</span> : null}
                {state.status === "stale" ? (
                  <button
                    type="button"
                    className="ml-1 underline"
                    onClick={() => aggregation.calculate(column.id)}
                  >
                    refresh
                  </button>
                ) : null}
              </>
            )}
          </span>
        ) : null}
      </div>
    </TableCell>
  )
}

export function DataTableFooter<TData>({
  table,
  aggregation,
}: {
  table: Table<TData>
  aggregation: FooterAggregationResult
}) {
  const hasAnyCalculable = Object.keys(aggregation.methods).length > 0
  if (!hasAnyCalculable) return null

  return (
    <TableFooter>
      <TableRow>
        {table.getVisibleLeafColumns().map((column) => (
          <FooterValueCell key={column.id} column={column} aggregation={aggregation} />
        ))}
      </TableRow>
    </TableFooter>
  )
}

"use client"

import * as React from "react"
import {
  getCoreRowModel,
  getPaginationRowModel,
  getSortedRowModel,
  useReactTable,
  type ColumnDef,
  type ColumnPinningState,
  type ColumnSizingState,
  type PaginationState,
  type RowSelectionState,
  type SortingState,
  type Table,
  type VisibilityState,
} from "@tanstack/react-table"

import { useGridNavigation } from "./use-grid-navigation"
import { buildRowGutterColumn, ROW_GUTTER_COLUMN_ID } from "./row-gutter"
import type { DataTableColumnMeta, DataTableRuntime } from "./types"

export type UseDataTableOptions<TData> = {
  data: TData[]
  columns: ColumnDef<TData, unknown>[]
  getRowId?: (row: TData, index: number) => string
  editable?: boolean
  onUpdateData?: (rowId: string, columnId: string, value: unknown) => void
  enablePagination?: boolean
  /** Prepends the row-number/selection gutter column. Defaults to false. */
  enableRowSelection?: boolean
  /** True when pagination is server-driven — loaded rows aren't necessarily all rows. Defaults to false. */
  manualPagination?: boolean
  /** Total row count across all pages/filters when manualPagination is true. */
  totalRowCount?: number
}

export type UseDataTableResult<TData> = {
  table: Table<TData>
  runtime: DataTableRuntime
}

export function useDataTable<TData>({
  data,
  columns,
  getRowId,
  editable = false,
  onUpdateData,
  enablePagination = true,
  enableRowSelection = false,
  manualPagination = false,
  totalRowCount,
}: UseDataTableOptions<TData>): UseDataTableResult<TData> {
  const [sorting, setSorting] = React.useState<SortingState>([])
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({})
  const [columnPinning, setColumnPinning] = React.useState<ColumnPinningState>({})
  const [columnSizing, setColumnSizing] = React.useState<ColumnSizingState>({})
  const [pagination, setPagination] = React.useState<PaginationState>({
    pageIndex: 0,
    pageSize: 50,
  })
  const [rowSelection, setRowSelection] = React.useState<RowSelectionState>({})
  const [isAllMatchingSelected, setIsAllMatchingSelectedState] = React.useState(false)

  const resolvedColumns = React.useMemo(
    () => (enableRowSelection ? [buildRowGutterColumn<TData>(), ...columns] : columns),
    [enableRowSelection, columns],
  )

  // React Compiler reports "Use of incompatible library" here: useReactTable
  // returns identity-stable functions it cannot safely memoize, so it skips
  // compiling this component. Expected with TanStack Table, harmless.
  const table = useReactTable<TData>({
    data,
    columns: resolvedColumns,
    getRowId: getRowId ?? ((row, index) => String(index)),
    state: {
      sorting,
      columnVisibility,
      columnPinning,
      columnSizing,
      rowSelection,
      ...(enablePagination ? { pagination } : {}),
    },
    onSortingChange: setSorting,
    onColumnVisibilityChange: setColumnVisibility,
    onColumnPinningChange: setColumnPinning,
    onColumnSizingChange: setColumnSizing,
    onRowSelectionChange: setRowSelection,
    onPaginationChange: setPagination,
    enableRowSelection,
    columnResizeMode: "onChange",
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    ...(enablePagination ? { getPaginationRowModel: getPaginationRowModel() } : {}),
    autoResetPageIndex: false,
  })

  // Deliberately asymmetric: turning matching ON also selects every loaded
  // row (so visible checkboxes agree with "everything"); turning it OFF does
  // NOT deselect — see DataTableRuntime.setAllMatchingSelected's doc comment
  // (types.ts) for why: the caller (row-gutter's header click-cycle) may be
  // narrowing from "all-matching" back to "all loaded" rather than to "none".
  const setAllMatchingSelected = React.useCallback(
    (matching: boolean) => {
      setIsAllMatchingSelectedState(matching)
      if (matching) table.toggleAllRowsSelected(true)
    },
    [table],
  )

  // Tracks the row a shift-click range should extend from, by id — the row
  // touched by the most recent plain (non-shift) toggle, or the far end of
  // the most recent shift-range. Deliberately an id, not a positional index:
  // TanStack's `Row.index` is fixed at row creation to the row's position in
  // the original, unsorted `data`, not its current on-screen position (see
  // row-gutter.tsx's `displayIndex` comment) — an index captured at click
  // time would point at the wrong row once sorting/filtering reorders the
  // table. Both the anchor's and the clicked row's actual positions are
  // resolved fresh from the live row model on every call instead.
  const lastToggledRowIdRef = React.useRef<string | null>(null)
  const toggleRowSelected = React.useCallback(
    (rowId: string, checked: boolean, shiftKey: boolean) => {
      const currentRows = table.getRowModel().rows
      const anchorId = lastToggledRowIdRef.current
      const anchorIndex = anchorId === null ? -1 : currentRows.findIndex((r) => r.id === anchorId)
      if (shiftKey && anchorIndex !== -1) {
        const clickedIndex = currentRows.findIndex((r) => r.id === rowId)
        if (clickedIndex !== -1) {
          const [start, end] =
            anchorIndex < clickedIndex ? [anchorIndex, clickedIndex] : [clickedIndex, anchorIndex]
          setRowSelection((prev) => {
            const next = { ...prev }
            for (let i = start; i <= end; i++) {
              const r = currentRows[i]
              if (r) next[r.id] = checked
            }
            return next
          })
        }
      } else {
        table.getRow(rowId)?.toggleSelected(checked)
      }
      lastToggledRowIdRef.current = rowId
    },
    [table],
  )

  const rows = table.getRowModel().rows
  const rowIds = React.useMemo(() => rows.map((r) => r.id), [rows])

  const visibleColumns = table.getVisibleLeafColumns()
  const columnIds = React.useMemo(
    () => visibleColumns.filter((c) => c.id !== ROW_GUTTER_COLUMN_ID).map((c) => c.id),
    [visibleColumns],
  )

  const isColumnEditable = React.useCallback(
    (columnId: string) => {
      const override = (
        table.getColumn(columnId)?.columnDef.meta as DataTableColumnMeta | undefined
      )?.editable
      return override ?? editable
    },
    [table, editable],
  )

  const nav = useGridNavigation({ rowIds, columnIds, isColumnEditable })

  // Revalidate activeCell when rowIds/columnIds change out from under it.
  //
  // use-grid-navigation.ts's module doc comment and the orphaned-id guard
  // inside its `moveActive` both explicitly delegate this responsibility to
  // use-data-table.ts. That guard only protects a single in-flight move: if
  // `current` points at a row/column id no longer in the live lists, it
  // holds still rather than guessing a replacement. Left unaddressed here,
  // that "hold still" becomes permanent — a sort, filter, delete, or (as in
  // the tests below) an entirely new `data` array can remove the active
  // row/column, and every subsequent arrow-key/Tab press would keep
  // resolving `rowIds.indexOf(current.rowId) === -1` and silently no-op,
  // freezing keyboard navigation with no visible active cell to recover
  // from.
  //
  // GridNavigation's public API only exposes `setActiveCell(pos: CellPos)`
  // — there is no way to clear activeCell to `null` from outside the hook.
  // Widening that already-shipped, already-reviewed hook's API (e.g. adding
  // a `clearActiveCell`) is a bigger change than this task calls for, so
  // instead: when the previous activeCell's row or column id has dropped
  // out of the new lists, snap to a *column-stable, clamped-index* cell via
  // the existing `setActiveCell` rather than leaving it dangling or jumping
  // all the way back to the first cell in the grid. Concretely (mirrors how
  // Excel/Sheets handle a row disappearing): if only the row vanished, stay
  // on the same column and move to whatever row now sits at the vanished
  // row's PREVIOUS index (clamped to the new list's bounds) — i.e. whatever
  // slid into that slot, or the new last row if it was the last one. If
  // only the column vanished, the same clamped-index logic applies to the
  // column, with the row preserved. If both vanished, both adjustments
  // apply independently. This avoids losing scroll position/context for a
  // user editing deep in the grid when only one nearby row/column changes.
  //
  // `prevIdsRef` exists solely to answer "what index was the vanished id at
  // *before* this change?" — the previous id lists are looked up here, then
  // the ref is updated to the current lists at the end of the effect so the
  // next run has the immediately-prior lists to compare against. (It is
  // NOT used to gate whether the effect body runs: the effect's dependency
  // array already means React only invokes this effect when `rowIds`/
  // `columnIds` change by reference, so a same-reference check here would
  // be dead code.)
  //
  // If the grid has no rows or no columns at all, there is no valid CellPos
  // to snap to; nav's internal activeCell state is left as-is in that case.
  // Nothing renders with `isActive` matching it (there's no cell to match),
  // so the stale value is inert until rows/columns exist again, at which
  // point this effect re-validates it on the next rowIds/columnIds change.
  const prevIdsRef = React.useRef({ rowIds, columnIds })
  React.useEffect(() => {
    const prev = prevIdsRef.current
    const active = nav.activeCell

    if (active) {
      const rowStillValid = rowIds.includes(active.rowId)
      const columnStillValid = columnIds.includes(active.columnId)

      if ((!rowStillValid || !columnStillValid) && rowIds.length > 0 && columnIds.length > 0) {
        const prevRowIdx = prev.rowIds.indexOf(active.rowId)
        const nextRowId = rowStillValid
          ? active.rowId
          : rowIds[Math.min(Math.max(prevRowIdx, 0), rowIds.length - 1)]

        const prevColIdx = prev.columnIds.indexOf(active.columnId)
        const nextColumnId = columnStillValid
          ? active.columnId
          : columnIds[Math.min(Math.max(prevColIdx, 0), columnIds.length - 1)]

        nav.setActiveCell({ rowId: nextRowId, columnId: nextColumnId })
      }
    }

    prevIdsRef.current = { rowIds, columnIds }
    // nav.activeCell is intentionally excluded: it's read fresh from `nav`
    // each time this effect actually runs (gated by rowIds/columnIds
    // identity), and including it would re-run this effect on every
    // click/navigation even when the id lists haven't changed.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [rowIds, columnIds, nav.setActiveCell])

  const updateData = React.useCallback(
    (rowId: string, columnId: string, value: unknown) => {
      onUpdateData?.(rowId, columnId, value)
    },
    [onUpdateData],
  )

  const runtime: DataTableRuntime = {
    ...nav,
    isColumnEditable,
    updateData,
    manualPagination,
    totalRowCount,
    isAllMatchingSelected,
    setAllMatchingSelected,
    toggleRowSelected,
  }

  return { table, runtime }
}

"use client"

import { flexRender, type Column, type ColumnDef } from "@tanstack/react-table"
import type * as React from "react"

import { Button } from "@/components/ui/button"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import { cn } from "@/lib/utils"

import { ColumnHeader } from "./column-header"
import { ColumnsMenu } from "./columns-menu"
import { DataTableRuntimeContext } from "./data-table-runtime-context"
import { DataTableFooter } from "./footer-aggregation"
import { useDataTable } from "./use-data-table"
import { useFooterAggregation } from "./use-footer-aggregation"
import type { CalculableColumn, ComputeAggregateArgs, DataTableColumnMeta } from "./types"

export type DataTableProps<TData> = {
  data: TData[]
  columns: ColumnDef<TData, unknown>[]
  getRowId?: (row: TData, index: number) => string
  editable?: boolean
  onUpdateData?: (rowId: string, columnId: string, value: unknown) => void
  enablePagination?: boolean
  enableRowSelection?: boolean
  manualPagination?: boolean
  totalRowCount?: number
  calculableColumns?: CalculableColumn[]
  computeAggregate?: (args: ComputeAggregateArgs) => Promise<number>
}

type PinnedCellStyle = { style: React.CSSProperties; className?: string }

// Pinned cells need their own background so they stay opaque over the
// scrolling columns behind them — but TableRow (components/ui/table.tsx)
// applies its hover/selected background as a CSS class on the <tr>, relying
// on <td>/<th> children being transparent so that background shows through.
// A plain inline `background` on the pinned cell would always beat the row's
// class (inline styles win over class-based pseudo-classes/variants), so on
// hover every column would highlight except the pinned ones. Instead, the
// background lives in `className` as arbitrary-variant ancestor selectors:
// `[tr:hover_&]`/`[tr[data-state=selected]_&]` target the pinned cell
// whenever it's a descendant of a hovered/selected <tr>, via a plain CSS
// descendant combinator — no `group` marker class required on TableRow.
// Deliberately NOT keyed off TableRow's `group` class (the earlier approach):
// `components/ui/table.tsx` is a `registryDependency: "table"` in this
// registry's items, so a fresh `npx shadcn add data-table` on a consumer
// project installs the stock, unmodified shadcn table.tsx with no `group`
// class — that would silently break pinned-column hover/selected
// highlighting for every real registry consumer even though it works in this
// repo. The ancestor-selector form has no such dependency. Sticky
// positioning, zIndex, and the box-shadow divider stay inline since they
// aren't state-dependent.
function pinnedStyle<TData>(column: Column<TData, unknown>): PinnedCellStyle {
  const pinned = column.getIsPinned()
  if (!pinned) return { style: {} }
  return {
    style: {
      position: "sticky",
      left: pinned === "left" ? column.getStart("left") : undefined,
      right: pinned === "right" ? column.getAfter("right") : undefined,
      zIndex: 1,
      boxShadow:
        pinned === "left"
          ? "1px 0 0 0 var(--border) inset"
          : "-1px 0 0 0 var(--border) inset",
    },
    className: "bg-background [tr:hover_&]:bg-muted/50 [tr[data-state=selected]_&]:bg-muted",
  }
}

export function DataTable<TData>(props: DataTableProps<TData>) {
  const { table, runtime } = useDataTable(props)
  const enablePagination = props.enablePagination ?? true
  const columnCount = table.getVisibleFlatColumns().length
  const aggregation = useFooterAggregation({
    table,
    calculableColumns: props.calculableColumns,
    computeAggregate: props.computeAggregate,
    manualPagination: props.manualPagination,
    totalRowCount: props.totalRowCount,
    isAllMatchingSelected: runtime.isAllMatchingSelected,
  })

  return (
    <DataTableRuntimeContext.Provider value={runtime}>
      <div className="space-y-3">
        <div className="flex items-center gap-2">
          <ColumnsMenu table={table} />
        </div>

        <div className="rounded-md border" onKeyDown={runtime.handleKeyDown}>
          <Table style={{ tableLayout: "fixed" }}>
            <TableHeader>
              {table.getHeaderGroups().map((headerGroup) => (
                <TableRow key={headerGroup.id}>
                  {headerGroup.headers.map((header) => {
                    const meta = header.column.columnDef.meta as DataTableColumnMeta | undefined
                    const pinned = pinnedStyle(header.column)
                    return (
                      <TableHead
                        key={header.id}
                        style={{ width: header.getSize(), ...pinned.style }}
                        className={cn("overflow-hidden text-ellipsis", pinned.className)}
                      >
                        {header.isPlaceholder ? null : meta ? (
                          <ColumnHeader column={header.column} label={meta.label} />
                        ) : (
                          // Structural columns (e.g. the row-gutter column)
                          // aren't built by defineColumns, so they carry no
                          // DataTableColumnMeta — flexRender their own
                          // columnDef.header instead of routing through
                          // ColumnHeader's label-only rendering, which would
                          // otherwise print the column id as plain text
                          // rather than invoking the column's header
                          // component (e.g. row-gutter's tri-state
                          // select-all checkbox).
                          flexRender(header.column.columnDef.header, header.getContext())
                        )}
                      </TableHead>
                    )
                  })}
                </TableRow>
              ))}
            </TableHeader>
            <TableBody>
              {table.getRowModel().rows.length === 0 ? (
                <TableRow>
                  <TableCell colSpan={columnCount} className="h-24 text-center text-muted-foreground">
                    No results.
                  </TableCell>
                </TableRow>
              ) : (
                table.getRowModel().rows.map((row) => (
                  <TableRow key={row.id} data-state={row.getIsSelected() ? "selected" : undefined}>
                    {row.getVisibleCells().map((cell) => {
                      const pinned = pinnedStyle(cell.column)
                      return (
                        <TableCell
                          key={cell.id}
                          style={{ width: cell.column.getSize(), ...pinned.style }}
                          className={cn("overflow-hidden p-0", pinned.className)}
                        >
                          {flexRender(cell.column.columnDef.cell, cell.getContext())}
                        </TableCell>
                      )
                    })}
                  </TableRow>
                ))
              )}
            </TableBody>
            <DataTableFooter table={table} aggregation={aggregation} />
          </Table>
        </div>

        {enablePagination && (
          <nav aria-label="Table pagination" className="flex items-center justify-end gap-2">
            <Button
              variant="outline"
              size="sm"
              aria-label="Previous page"
              onClick={() => table.previousPage()}
              disabled={!table.getCanPreviousPage()}
            >
              Previous
            </Button>
            <span className="text-sm text-muted-foreground">
              Page {table.getState().pagination.pageIndex + 1} of {table.getPageCount()}
            </span>
            <Button
              variant="outline"
              size="sm"
              aria-label="Next page"
              onClick={() => table.nextPage()}
              disabled={!table.getCanNextPage()}
            >
              Next
            </Button>
          </nav>
        )}
      </div>
    </DataTableRuntimeContext.Provider>
  )
}
